mapper.select:
${pagingTop} SELECT TERMS_IDX, TERMS_TYPE, TITLE, CONTENTS, USE_YN, DELETE_YN, ADD_ID, TO_CHAR(ADD_DATE,'YYYY-MM-DD') AS ADD_DATE, MODIFY_ID, MODIFY_DATE, (SELECT A.CODE_NAME FROM CMS_CODE A WHERE A.GROUP_ID = 'C0015' AND A.CODE_ID = CMS_TERMS.TERMS_TYPE) AS TERMS_TYPE_NAME FROM CMS_TERMS WHERE DELETE_YN = 'N'
AND ${search_type} LIKE '%'||#{search_text}||'%'
ORDER BY TERMS_IDX ASC ${pagingBottom}
